DO $$
BEGIN
  IF NOT EXISTS (SELECT FROM pg_user WHERE usename = 'quran_app') THEN
    CREATE USER quran_app WITH PASSWORD 'quran_app_pass' NOSUPERUSER;
  END IF;
END $$;

GRANT CONNECT ON DATABASE quran_school TO quran_app;
GRANT USAGE ON SCHEMA public TO quran_app;
GRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA public TO quran_app;
GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO quran_app;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA public TO quran_app;
ALTER DEFAULT PRIVILEGES IN SCHEMA public GRANT SELECT, INSERT, UPDATE, DELETE ON TABLES TO quran_app;
ALTER DEFAULT PRIVILEGES IN SCHEMA public GRANT USAGE, SELECT ON SEQUENCES TO quran_app;

