SELECT tablename, relrowsecurity, relforcerowsecurity
FROM pg_class
JOIN pg_tables ON relname = tablename
WHERE schemaname = 'public'
  AND tablename IN ('students','groups','student_groups','attendance','memorization_logs','users');

